import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { teamsAPI } from '../api';

export default function Teams() {
  const [teams, setTeams] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [name, setName] = useState('');
  const [editId, setEditId] = useState(null);
  const [error, setError] = useState('');

  const load = () => teamsAPI.getAll().then(d => { setTeams(d); setLoading(false); });
  useEffect(() => { load(); }, []);

  const submit = async (e) => {
    e.preventDefault();
    setError('');
    try {
      if (editId) {
        await teamsAPI.update(editId, { name });
      } else {
        await teamsAPI.create({ name });
      }
      setName(''); setEditId(null); setShowForm(false);
      load();
    } catch (err) {
      setError(err.response?.data?.error || 'Something went wrong');
    }
  };

  const deleteTeam = async (id) => {
    if (!window.confirm('Delete this team and all its data?')) return;
    await teamsAPI.delete(id);
    load();
  };

  const startEdit = (team) => { setEditId(team.id); setName(team.name); setShowForm(true); };
  const cancelForm = () => { setShowForm(false); setName(''); setEditId(null); setError(''); };

  if (loading) return <div className="flex justify-center py-20 text-emerald-700/70">Loading...</div>;

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between">
        <h1 className="title-xl">Teams</h1>
        <button onClick={() => setShowForm(true)} className="btn-primary px-4 py-2 text-sm">
          + New Team
        </button>
      </div>

      {showForm && (
        <div className="panel p-5 fade-in">
          <h2 className="font-semibold mb-3 text-emerald-900">{editId ? 'Edit Team' : 'New Team'}</h2>
          <form onSubmit={submit} className="flex gap-3 items-end">
            <div className="flex-1">
              <label className="block text-sm text-emerald-900/80 mb-1">Team Name</label>
              <input
                value={name} onChange={e => setName(e.target.value)}
                className="w-full field text-sm"
                placeholder="e.g. Team Alpha" autoFocus required
              />
              {error && <p className="text-red-500 text-xs mt-1">{error}</p>}
            </div>
            <button type="submit" className="btn-primary px-4 py-2 text-sm">
              {editId ? 'Update' : 'Create'}
            </button>
            <button type="button" onClick={cancelForm} className="btn-muted px-4 py-2 text-sm">Cancel</button>
          </form>
        </div>
      )}

      {teams.length === 0 ? (
        <div className="panel text-center py-16 text-emerald-800/55">
          <p className="text-5xl mb-3">👥</p>
          <p className="text-lg">No teams yet. Create your first team!</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {teams.map(team => (
            <div key={team.id} className="panel hover:-translate-y-0.5 transition-all duration-200">
              <div className="p-5">
                <div className="flex items-start justify-between">
                  <div>
                    <h3 className="font-bold text-emerald-950 text-lg">{team.name}</h3>
                    <p className="text-sm text-emerald-900/70 mt-1">
                      <span className="text-emerald-700 font-medium">{team.player_count}</span> player{team.player_count !== 1 ? 's' : ''}
                    </p>
                    <p className="text-xs text-emerald-900/50 mt-1">Created {new Date(team.created_at).toLocaleDateString()}</p>
                  </div>
                  <div className="flex gap-2">
                    <button onClick={() => startEdit(team)} className="text-gray-400 hover:text-blue-500 text-sm p-1">✏️</button>
                    <button onClick={() => deleteTeam(team.id)} className="text-gray-400 hover:text-red-500 text-sm p-1">🗑️</button>
                  </div>
                </div>
              </div>
              <div className="border-t border-emerald-100 px-5 py-3 flex items-center justify-between bg-emerald-50/60 rounded-b-[18px]">
                <Link to={`/teams/${team.id}`} className="text-sm text-emerald-700 font-medium hover:underline">
                  Manage Players →
                </Link>
                <Link to={`/matches?team_id=${team.id}`} className="text-sm text-teal-700 hover:underline">
                  View Matches
                </Link>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
